const fs = require("fs");
const path = require("path");
const descriptions = require("./data/gear-descriptions.js");

function dollarQuote(text) {
  let tag = "d";
  while (text.includes(`$${tag}$`)) tag += "x";
  return `$${tag}$${text}$${tag}$`;
}

const values = Object.entries(descriptions)
  .map(([slug, text]) => `  ('${slug}', ${dollarQuote(text)})`)
  .join(",\n");

const sql = `-- Complete truncated gear/focus descriptions (PHB 2024 PT-BR)
-- Generated by scripts/generate-gear-descriptions-seed.js — review before apply

UPDATE rpg.phb_item AS i
SET description = v.description
FROM (VALUES
${values}
) AS v(slug, description)
WHERE i.slug = v.slug;
`;

const out = path.join(
  __dirname,
  "../database/seeds/phb/S070_phb_item_gear_descriptions.sql",
);
fs.writeFileSync(out, sql, "utf8");
console.log("Wrote", out, "rows:", Object.keys(descriptions).length);
